class FenwickTree(val size: Int) {
  private val tree = Array.ofDim[Int](size + 1)
  def update(pos: Int, delta: Int): Unit = {
    var i = pos
    while (i <= size) {
      tree(i) += delta
      i += i & -i
    }
  }
  def query(pos: Int): Int = {
    var res = 0
    var i = pos
    while (i > 0) {
      res += tree(i)
      i -= i & -i
    }
    res
  }
  def rangeSum(l: Int, r: Int): Int = {
    if (l > r) 0 else query(r) - query(l - 1)
  }
}

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
