class FenwickTree(val size: Int) {
  private val tree = Array.fill(size + 1)(0)
  def update(pos: Int, delta: Int): Unit = {
    var i = pos
    while (i <= size) {
      tree(i) += delta
      i += i & -i
    }
  }
  def query(pos: Int): Int = {
    var res = 0
    var i = pos
    while (i > 0) {
      res += tree(i)
      i -= i & -i
    }
    res
  }
  def rangeQuery(l: Int, r: Int): Int = {
    if (l > r) 0
    else query(r) - query(l - 1)
  }
}

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val n = nums.length
  val maxDepth = 5
  val fenwickTrees = Array.fill(maxDepth + 1)(new FenwickTree(n))

  val depths = Array.fill(n)(0)
  for (i <- 0 until n) {
    depths(i) = computeDepth(nums(i))
  }

  for (i <- 0 until n) {
    val d = depths(i)
    if (d <= maxDepth) {
      fenwickTrees(d).update(i + 1, 1)
    }
  }

  val answer = Array.ofDim[Long](queries.length)
  for (qIdx <- 0 until queries.length) {
    val q = queries(qIdx)
    if (q(0) == 1) {
      val l = q(1).toInt
      val r = q(2).toInt
      val k = q(3).toInt
      val count = fenwickTrees(k).rangeQuery(l + 1, r + 1)
      answer(qIdx) = count.toLong
    } else {
      val idx = q(1).toInt
      val val = q(2).toLong
      val oldD = depths(idx)
      if (oldD <= maxDepth) {
        fenwickTrees(oldD).update(idx + 1, -1)
      }
      val newD = computeDepth(val)
      if (newD <= maxDepth) {
        fenwickTrees(newD).update(idx + 1, 1)
      }
      nums(idx) = val
      depths(idx) = newD
    }
  }
  answer
}

def computeDepth(x: Long): Int = {
  var current = x
  var d = 0
  while (current != 1) {
    current = (current).toBinaryString.count('1')
    d += 1
  }
  d
