    while (i > 0) {
      res += tree(i)
      i -= i & -i
    }
    res
  }
}

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val n = nums.length
  val ft = Array.fill(4)(new FenwickTree(n))
